#include <CL/cl.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include "../common.h"
#include "../util/timer/timer.h"
#include "../util/opencl/opencl.h"

// Device kernel source embedded as a string
const char *kernel_source_str = 
"#pragma OPENCL EXTENSION cl_khr_fp64 : enable\n"
"typedef struct record { int value; } record;\n"
"typedef struct knode { int location; int indices[256+1]; int keys[256+1]; char is_leaf; int num_keys; } knode;\n"
"__kernel void findK(long maxheight, __global knode *knodes, long knodes_elem, __global record *records, __global long *currKnode, __global long *offset, __global int *keys, __global record *ans) {\n"
"    int bid = get_group_id(0); int thid = get_local_id(0); int threadsPerBlock = get_local_size(0);\n"
"    int i; long current_offset = offset[bid]; long current_knode = currKnode[bid];\n"
"    for(i = 0; i < maxheight; i++) {\n"
"        if(thid < threadsPerBlock) {\n"
"            if(keys[bid] >= knodes[current_knode].keys[thid] && keys[bid] < knodes[current_knode].keys[thid+1]) {\n"
"                if(knodes_elem > knodes[current_offset].indices[thid]) current_offset = knodes[current_offset].indices[thid];\n"
"            }\n"
"        }\n"
"        if(thid == 0) { currKnode[bid] = current_offset; current_knode = current_offset; }\n"
"    }\n"
"    if(thid < threadsPerBlock) {\n"
"        if(keys[bid] == knodes[current_knode].keys[thid]) ans[bid].value = records[knodes[current_knode].indices[thid]].value;\n"
"    }\n"
"}";

void kernel_cpu(int cores_arg, record *records, knode *knodes, long knodes_elem, int order, long maxheight, int count, long *currKnode, long *offset, int *keys, record *ans) {
    long long time0, time1, time2;
    time0 = get_time();

    cl_int error;
    cl_uint num_platforms;
    error = clGetPlatformIDs(0, NULL, &num_platforms);
    if (error != CL_SUCCESS) { fprintf(stderr, "Failed to get platforms\n"); exit(1); }

    cl_platform_id *platforms = malloc(sizeof(cl_platform_id) * num_platforms);
    clGetPlatformIDs(num_platforms, platforms, NULL);
    cl_platform_id platform = platforms[0];
    free(platforms);

    cl_uint num_devices;
    clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, 0, NULL, &num_devices);
    if (num_devices == 0) { fprintf(stderr, "No devices found\n"); exit(1); }

    cl_device_id *devices = malloc(sizeof(cl_device_id) * num_devices);
    clGetDeviceIDs(platform, CL_DEVICE_TYPE_ALL, num_devices, devices, NULL);
    cl_device_id device = devices[0];
    free(devices);

    cl_context context = clCreateContext(NULL, 1, &device, NULL, NULL, &error);
    if (error != CL_SUCCESS) { fprintf(stderr, "Failed to create context\n"); exit(1); }

    cl_command_queue queue = clCreateCommandQueue(context, device, 0, &error);
    if (error != CL_SUCCESS) { fprintf(stderr, "Failed to create queue\n"); exit(1); }

    time1 = get_time();

    // Create buffers
    cl_mem records_buf = clCreateBuffer(context, CL_MEM_READ_ONLY | CL_MEM_COPY_HOST_PTR, sizeof(record) * knodes_elem, records, &error);
    cl_mem knodes_buf = clCreateBuffer(context, CL_MEM_READ_ONLY | CL_MEM_COPY_HOST_PTR, sizeof(knode) * knodes_elem, knodes, &error);
    cl_mem currKnode_buf = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR, sizeof(long) * count, currKnode, &error);
    cl_mem offset_buf = clCreateBuffer(context, CL_MEM_READ_WRITE | CL_MEM_COPY_HOST_PTR, sizeof(long) * count, offset, &error);
    cl_mem keys_buf = clCreateBuffer(context, CL_MEM_READ_ONLY | CL_MEM_COPY_HOST_PTR, sizeof(int) * count, keys, &error);
    cl_mem ans_buf = clCreateBuffer(context, CL_MEM_WRITE_ONLY | CL_MEM_COPY_HOST_PTR, sizeof(record) * count, ans, &error);

    // Create program and kernel
    cl_program program = clCreateProgramWithSource(context, 1, &kernel_source_str, NULL, &error);
    char options[64];
    sprintf(options, "-DDEFAULT_ORDER=%d", order);
    clBuildProgram(program, 1, &device, options, NULL, NULL);

    cl_kernel kernel = clCreateKernel(program, "findK", &error);

    // Set args
    clSetKernelArg(kernel, 0, sizeof(long), &maxheight);
    clSetKernelArg(kernel, 1, sizeof(cl_mem), &knodes_buf);
    clSetKernelArg(kernel, 2, sizeof(long), &knodes_elem);
    clSetKernelArg(kernel, 3, sizeof(cl_mem), &records_buf);
    clSetKernelArg(kernel, 4, sizeof(cl_mem), &currKnode_buf);
    clSetKernelArg(kernel, 5, sizeof(cl_mem), &offset_buf);
    clSetKernelArg(kernel, 6, sizeof(cl_mem), &keys_buf);
    clSetKernelArg(kernel, 7, sizeof(cl_mem), &ans_buf);

    // Execute
    size_t local_size = order < 1024 ? order : 1024;
    size_t global_size = count * local_size;
    clEnqueueNDRangeKernel(queue, kernel, 1, NULL, &global_size, &local_size, 0, NULL, NULL);
    clFinish(queue);

    // Read back
    clEnqueueReadBuffer(queue, ans_buf, CL_TRUE, 0, sizeof(record) * count, ans, 0, NULL, NULL);

    time2 = get_time();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n", (float)(time1-time0)/1000000, (float)(time1-time0)/(float)(time2-time0)*100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n", (float)(time2-time1)/1000000, (float)(time2-time1)/(float)(time2-time0)*100);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time2-time0)/1000000);

    // Cleanup
    clReleaseMemObject(records_buf);
    clReleaseMemObject(knodes_buf);
    clReleaseMemObject(currKnode_buf);
    clReleaseMemObject(offset_buf);
    clReleaseMemObject(keys_buf);
    clReleaseMemObject(ans_buf);
    clReleaseKernel(kernel);
    clReleaseProgram(program);
    clReleaseCommandQueue(queue);
    clReleaseContext(context);
}

